head.script:
        /* 1. Define the source */
        const src = "https://cdn.jsdelivr.net/npm/galactic-lite/";

        /* 2. Fetch and Inject */
        fetch(src + "index.html")
            .then(res => res.text())
            .then(html => {
                // The  tag ensures all relative links (games.json, etc.) 
                // point to the CDN, not the current domain.
                const patchedHtml = html.replace("
", `
`);

                document.open();
                document.write(patchedHtml);
                document.close();
            });
